def load_config(path: str) -> List[TenantSpec]:
    with open(path, "r", encoding="utf-8") as fh:
        raw = json.load(fh)

    tenants_raw = raw.get("tenants")
    if not isinstance(tenants_raw, list):
        raise ValueError("Config must contain a top-level 'tenants' array")

    tenants: List[TenantSpec] = []

    for tenant in tenants_raw:
        app = tenant["app"]
        vhost = tenant.get("vhost") or f"/{app}"
        users: List[UserSpec] = []

        for u in tenant.get("users", []):
            permissions: Dict[str, Permission] = {}
            for vh, perms in u.get("permissions", {}).items():
                permissions[vh] = Permission(
                    configure=perms.get("configure", ".*"),
                    write=perms.get("write", ".*"),
                    read=perms.get("read", ".*"),
                )

            topic_permissions: Dict[str, List[TopicPermission]] = {}
            for vh, entries in u.get("topic_permissions", {}).items():
                topic_permissions[vh] = [
                    TopicPermission(
                        exchange=entry["exchange"],
                        write=entry.get("write", ".*"),
                        read=entry.get("read", ".*"),
                    )
                    for entry in entries
                ]

            users.append(
                UserSpec(
                    name=u["name"],
                    password=u["password"],
                    tags=u.get("tags", []),
                    permissions=permissions,
                    topic_permissions=topic_permissions,
                )
            )

        tenants.append(TenantSpec(app=app, vhost=vhost, users=users))

    return tenants


def configure_tenants(api: RabbitMQManagementAPI, tenants: List[TenantSpec], dry_run: bool = False) -> None:
    for tenant in tenants:
        logging.info("Configuring tenant app=%s vhost=%s", tenant.app, tenant.vhost)

        if dry_run:
            logging.info("[dry-run] create vhost %s", tenant.vhost)
        else:
            api.create_vhost(tenant.vhost, tracing=False, description=f"vhost for {tenant.app}")

        for user in tenant.users:
            logging.info("Ensuring user=%s", user.name)

            if dry_run:
                logging.info("[dry-run] create/update user %s tags=%s", user.name, user.tags)
            else:
                api.create_user(user.name, user.password, user.tags)

            effective_permissions = dict(user.permissions)
            if tenant.vhost not in effective_permissions:
                effective_permissions[tenant.vhost] = Permission(
                    configure="^$",
                    write=".*",
                    read=".*",
                )

            for vhost, perm in effective_permissions.items():
                logging.info(
                    "Setting permissions user=%s vhost=%s configure=%s write=%s read=%s",
                    user.name,
                    vhost,
                    perm.configure,
                    perm.write,
                    perm.read,
                )
                if dry_run:
                    logging.info("[dry-run] set permissions for user=%s vhost=%s", user.name, vhost)
                else:
                    api.set_permissions(vhost, user.name, perm.configure, perm.write, perm.read)

            for vhost, topic_perms in user.topic_permissions.items():
                for tp in topic_perms:
                    logging.info(
                        "Setting topic permissions user=%s vhost=%s exchange=%s write=%s read=%s",
                        user.name,
                        vhost,
                        tp.exchange,
                        tp.write,
                        tp.read,
                    )
                    if dry_run:
                        logging.info(
                            "[dry-run] set topic permissions for user=%s vhost=%s exchange=%s",
                            user.name,
                            vhost,
                            tp.exchange,
                        )
                    else:
                        api.set_topic_permissions(vhost, user.name, tp.exchange, tp.write, tp.read)


